Essential table functions:
```m
// Filter rows
Table.SelectRows(Source, each [Amount] > 0 and [Region] = "EMEA")

// Add computed column
Table.AddColumn(Source, "MonthDate", each #date([Year], [Month], 1), type date)

// Cast types in one step
Table.TransformColumnTypes(Source, {
    {"Date", type date}, {"Amount", Currency.Type},
    {"Quantity", Int64.Type}, {"Name", type text}
})

// Rename columns
Table.RenameColumns(Source, {{"old_name", "New Name"}, {"qty", "Quantity"}})

// Keep/remove columns
Table.SelectColumns(Source, {"Date", "Category", "Amount"})
Table.RemoveColumns(Source, {"Content", "Extension", "Attributes"})

// Promote first row to headers
Table.PromoteHeaders(Source, [PromoteAllScalars=true])

// Combine multiple tables
Table.Combine({Table1, Table2, Table3})

// Group and aggregate
Table.Group(Source, {"Year", "Month"}, {
    {"Total", each List.Sum([Amount]), type number},
    {"Count", each Table.RowCount(_), Int64.Type}
})

// Join two tables
Table.Join(Sales, "ProductID", Products, "ProductID", JoinKind.Left)

// Sort
Table.Sort(Source, {{"Year", Order.Ascending}, {"Month", Order.Ascending}})

// Unpivot wide to tall
Table.UnpivotOtherColumns(Source, {"Date", "SourceFile"}, "MetricName", "Value")

// Expand nested table column
Table.ExpandTableColumn(Source, "Data", Table.ColumnNames(Source{0}[Data]))
```
